package com.example.mfa.controller;

import com.example.mfa.entity.User;
import com.example.mfa.service.BackupCodeService;
import com.example.mfa.service.MfaService;
import com.example.mfa.service.UserService;
import com.example.mfa.util.QrCodeGenerator;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.mvc.support.RedirectAttributes;

import java.util.List;
import java.util.Optional;

@Controller
@RequestMapping("/mfa")
public class MfaController {

    private final MfaService mfaService;
    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public MfaController(MfaService mfaService, UserService userService, BackupCodeService backupCodeService) {
        this.mfaService = mfaService;
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    @GetMapping("/setup")
    public String showMfaSetup(Model model) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        if (currentUser.isMfaEnabled()) {
            model.addAttribute("mfaEnabled", true);
            return "mfa-setup";
        }

        String secret = mfaService.generateMfaSecret();
        String issuer = "MfaApp"; // Your application name
        String accountName = currentUser.getUsername();
        String otpAuthUrl = mfaService.generateOtpAuthUrl(secret, issuer, accountName);

        try {
            String qrCodeImage = QrCodeGenerator.generateQrCodeImage(otpAuthUrl, 200, 200);
            model.addAttribute("qrCodeImage", qrCodeImage);
            model.addAttribute("secret", secret);
            model.addAttribute("mfaEnabled", false);
        } catch (Exception e) {
            model.addAttribute("errorMessage", "Error generating QR code: " + e.getMessage());
        }
        return "mfa-setup";
    }

    @PostMapping("/enable")
    public String enableMfa(@RequestParam("secret") String secret,
                            @RequestParam("code") String code,
                            RedirectAttributes redirectAttributes) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();

        if (mfaService.verifyTotpCode(secret, code)) {
            userService.enableMfa(currentUser.getUsername(), secret);
            List<String> backupCodes = backupCodeService.generateAndStoreBackupCodes(currentUser);
            redirectAttributes.addFlashAttribute("backupCodes", backupCodes);
            redirectAttributes.addFlashAttribute("successMessage", "MFA enabled successfully! Please save your backup codes.");
            return "redirect:/mfa/backup-codes";
        } else {
            redirectAttributes.addFlashAttribute("errorMessage", "Invalid MFA code. Please try again.");
            return "redirect:/mfa/setup";
        }
    }

    @GetMapping("/backup-codes")
    public String showBackupCodes(Model model) {
        // Backup codes are passed via flash attributes from the /mfa/enable POST request
        if (!model.containsAttribute("backupCodes")) {
            // If somehow user navigates directly, we might not have them.
            // In a real app, you might re-generate, or just show a message.
            model.addAttribute("infoMessage", "Backup codes are generated only once during MFA setup. You can regenerate them in your profile settings.");
        }
        return "mfa-backup-codes";
    }

    @PostMapping("/disable")
    public String disableMfa(RedirectAttributes redirectAttributes) {
        User currentUser = (User) SecurityContextHolder.getContext().getAuthentication().getPrincipal();
        userService.disableMfa(currentUser.getUsername());
        backupCodeService.deleteAllBackupCodesForUser(currentUser);
        redirectAttributes.addFlashAttribute("successMessage", "MFA disabled successfully. All backup codes have been invalidated.");
        return "redirect:/mfa/setup";
    }

    @GetMapping("/verify")
    public String showMfaVerification(HttpSession session, Model model) {
        Authentication pendingAuth = (Authentication) session.getAttribute("PENDING_MFA_AUTHENTICATION");
        if (pendingAuth == null) {
            return "redirect:/login"; // No pending authentication
        }
        return "mfa-verify";
    }

    @PostMapping("/verify")
    public String verifyMfaCode(@RequestParam("code") String code,
                                HttpSession session,
                                RedirectAttributes redirectAttributes) {
        Authentication pendingAuth = (Authentication) session.getAttribute("PENDING_MFA_AUTHENTICATION");
        if (pendingAuth == null) {
            return "redirect:/login";
        }

        User user = (User) pendingAuth.getPrincipal();
        Optional<User> storedUser = userService.findByUsername(user.getUsername());

        if (storedUser.isPresent() && storedUser.get().isMfaEnabled() && storedUser.get().getMfaSecret() != null) {
            if (mfaService.verifyTotpCode(storedUser.get().getMfaSecret(), code)) {
                // MFA successful, fully authenticate the user
                SecurityContextHolder.getContext().setAuthentication(pendingAuth);
                session.removeAttribute("PENDING_MFA_AUTHENTICATION");
                return "redirect:/dashboard";
            } else {
                redirectAttributes.addFlashAttribute("errorMessage", "Invalid MFA code.");
                return "redirect:/mfa/verify";
            }
        }
        // Should not happen if MFA is enabled but secret is null or user not found
        redirectAttributes.addFlashAttribute("errorMessage", "MFA setup error or user not found.");
        return "redirect:/login";
    }

    @GetMapping("/backup-verify")
    public String showBackupCodeVerification(HttpSession session, Model model) {
        Authentication pendingAuth = (Authentication) session.getAttribute("PENDING_MFA_AUTHENTICATION");
        if (pendingAuth == null) {
            return "redirect:/login";
        }
        return "backup-code-verify";
    }

    @PostMapping("/backup-verify")
    public String verifyBackupCode(@RequestParam("backupCode") String backupCode,
                                   HttpSession session,
                                   RedirectAttributes redirectAttributes) {
        Authentication pendingAuth = (Authentication) session.getAttribute("PENDING_MFA_AUTHENTICATION");
        if (pendingAuth == null) {
            return "redirect:/login";
        }

        User user = (User) pendingAuth.getPrincipal();
        Optional<User> storedUser = userService.findByUsername(user.getUsername());

        if (storedUser.isPresent()) {
            if (backupCodeService.verifyAndUseBackupCode(storedUser.get(), backupCode)) {
                // Backup code successful, fully authenticate the user
                SecurityContextHolder.getContext().setAuthentication(pendingAuth);
                session.removeAttribute("PENDING_MFA_AUTHENTICATION");
                redirectAttributes.addFlashAttribute("successMessage", "Logged in using backup code.");
                return "redirect:/dashboard";
            } else {
                redirectAttributes.addFlashAttribute("errorMessage", "Invalid or used backup code.");
                return "redirect:/mfa/backup-verify";
            }
        }
        redirectAttributes.addFlashAttribute("errorMessage", "Authentication error.");
        return "redirect:/login";
    }
}


