package com.example.mfa.service;

import com.example.mfa.entity.BackupCode;
import com.example.mfa.entity.User;
import com.example.mfa.repository.BackupCodeRepository;
import jakarta.transaction.Transactional;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
public class BackupCodeService {

    private static final int NUMBER_OF_BACKUP_CODES = 5;
    private static final int BACKUP_CODE_LENGTH = 10; // e.g., 10 alphanumeric characters

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateAndStoreBackupCodes(User user) {
        // Invalidate old codes first
        deleteAllBackupCodesForUser(user);

        List<String> rawCodes = new ArrayList<>();
        List<BackupCode> backupCodesToStore = new ArrayList<>();
        SecureRandom random = new SecureRandom();

        for (int i = 0; i < NUMBER_OF_BACKUP_CODES; i++) {
            String rawCode = generateRandomCode(random);
            String hashedCode = passwordEncoder.encode(rawCode); // Use password encoder for consistency
            backupCodesToStore.add(new BackupCode(user, hashedCode));
            rawCodes.add(rawCode);
        }
        backupCodeRepository.saveAll(backupCodesToStore);
        return rawCodes;
    }

    private String generateRandomCode(SecureRandom random) {
        String chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        StringBuilder sb = new StringBuilder(BACKUP_CODE_LENGTH);
        for (int i = 0; i < BACKUP_CODE_LENGTH; i++) {
            sb.append(chars.charAt(random.nextInt(chars.length())));
        }
        return sb.toString();
    }

    @Transactional
    public boolean verifyAndUseBackupCode(User user, String providedCode) {
        List<BackupCode> userBackupCodes = backupCodeRepository.findByUser(user);

        Optional<BackupCode> matchingCode = userBackupCodes.stream()
                .filter(bc -> !bc.isUsed() && passwordEncoder.matches(providedCode, bc.getHashedCode()))
                .findFirst();

        if (matchingCode.isPresent()) {
            BackupCode code = matchingCode.get();
            code.setUsed(true);
            backupCodeRepository.save(code);
            return true;
        }
        return false;
    }

    @Transactional
    public void deleteAllBackupCodesForUser(User user) {
        backupCodeRepository.deleteByUser(user);
    }

    public List<String> getRemainingBackupCodes(User user) {
        return backupCodeRepository.findByUser(user).stream()
                .filter(bc -> !bc.isUsed())
                .map(BackupCode::getHashedCode) // Return hashed for display if needed, or just count
                .collect(Collectors.toList());
    }
}


